mapper.select:
SELECT a.site_code as siteCode, a.site_name as siteName, a.company as company, a.site_type as siteType, a.site_model as siteModel, a.STATUS as status, a.commission_plan as commissionPlan, a.bk_name as bkName, a.site_prefix as sitePrefix, a.skin as skin, a.long_logo as longLogo, a.short_logo as shortLogo, (select group_concat(code separator ',') from language_manager where site_code = a.site_code group by site_code) as language, (select group_concat(plat_currency_code separator ',') from site_currency_info where site_code = a.site_code group by site_code) as currency, a.site_admin_account as siteAdminAccount, a.remark as remark, a.created_time as createTime, a.updated_time as operatorTime, a.updater as operator FROM site_info a WHERE 1 = 1
and a.site_code like concat ('%', #{siteVO.siteCode},'%')
and a.site_name like concat ('%', #{siteVO.siteName},'%')
and a.company like concat ('%', #{siteVO.company},'%')
and a.site_model = #{siteVO.siteModel}
and a.status = #{siteVO.status}
AND a.updated_time >= #{siteVO.startTime}
AND a.updated_time <= #{siteVO.endTime}
order by a.status , a.updated_time desc
